-- Ward NPCs + preop optimization + progression + procedure locations.
-- Repo copy of migration ward_preop_progression (applied 2026-07-10, data_version 78).
-- Regenerate: node game/tools/gen_ward_sql.js > db/seed_ward_preop.sql

-- 1. procedure_game_params: level gate, standard-of-care location, preop rules
alter table public.procedure_game_params
  add column if not exists min_level int not null default 1,
  add column if not exists location text not null default 'ir_suite',
  add column if not exists preop jsonb not null default '{}';
do $$ begin
  alter table public.procedure_game_params
    add constraint procedure_game_params_location_check
    check (location in ('ir_suite','ct_suite','us_room','bedside'));
exception when duplicate_object then null; end $$;

-- 2. v_game_ready surfaces the gate + location to the client
create or replace view public.v_game_ready
with (security_invoker = true) as
select p.id, p.title, p.category_id, g.pacing, g.complexity, g.min_level, g.location
from public.procedures p
join public.procedure_game_params g on g.procedure_id = p.id
join public.vessel_maps vm          on vm.id = g.vessel_map_id
where p.status = 'published'
  and exists (select 1 from public.patient_generators pg
              where pg.procedure_id = p.id and pg.status = 'published')
  and exists (select 1 from public.complications c
              where (c.procedure_id = p.id or c.procedure_id is null)
                and c.status = 'published');

-- 3. Chest port: fluoroscopy suite [1]; preop CITED to [1]; min_level DESIGN.
update public.procedure_game_params set
  min_level = 1, location = 'ir_suite',
  preop = $steps${"labs":[{"id":"inr","label":"INR","kind":"max","limit":1.5,"required":true,"canBeMissing":true,"goalText":"goal < 1.5","cite":"Routine INR in all patients; goal < 1.5 [1]","derange":[1.7,3.4],"violation":{"score":[{"cat":"safety","delta":-6,"reason":"Proceeded with INR above the 1.5 goal for a moderate-bleeding-risk procedure without correction.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":3,"basis":"MODELED multiplier"}]},"missingViolation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded without a documented INR (routine for all patients).","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":1.5,"basis":"MODELED multiplier"}]}},{"id":"platelets","label":"Platelet count","kind":"min","limit":50,"required":false,"goalText":"transfuse if < 50 ×10⁹/L","cite":"Transfusion recommended for counts < 50,000/µL [1]","derange":[22,46],"violation":{"score":[{"cat":"safety","delta":-5,"reason":"Proceeded with platelets < 50 ×10⁹/L without transfusion.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":3,"basis":"MODELED — mirrors the engine's multLow"}]}},{"id":"ptt","label":"PTT","kind":"max","limit":52.5,"required":false,"onlyIf":"on_anticoagulant","goalText":"< 1.5× control (normal 25–35 s)","cite":"PTT recommended on IV unfractionated heparin; < 1.5× control [1]","derange":[60,95],"violation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded on anticoagulation with PTT > 1.5× control.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":2,"basis":"MODELED multiplier"}]}}],"contraindications":[{"id":"bacteremia","label":"Bacteremia / sepsis","cite":"Absolute contraindication [1]","emr":"Febrile to 38.9 °C overnight; 2/2 blood culture bottles growing gram-negative rods; on empiric antibiotics.","violation":{"score":[{"cat":"safety","delta":-15,"reason":"Implanted a subcutaneous port in an actively bacteremic patient.","cite":"Absolute contraindications [1]"}],"postop":"POD 5: port pocket infection with persistent bacteremia — device explanted, PICC bridge while clearing cultures."}},{"id":"cellulitis","label":"Cellulitis at the insertion site","cite":"Absolute contraindication [1]","emr":"Warm, indurated erythema over the right anterior chest and lower neck at the planned insertion site.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Placed the port through cellulitic skin.","cite":"Absolute contraindications [1]"}],"postop":"Early pocket infection tracking from the cellulitic entry — explant and IV antibiotics."}},{"id":"allergy","label":"Allergy to catheter material","cite":"Absolute contraindication [1]","emr":"Allergy list: documented severe reaction to the implant catheter material.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Implanted a device the patient has a documented material allergy to.","cite":"Absolute contraindications [1]"}],"postop":"Progressive local reaction around the pocket — device removed."}}]}$steps$::jsonb,
  case_steps = $steps$[{"n":1,"title":"Time-out","node":"rij_access","best":"timeout","prompt":"Pre-procedure. How do you begin?","teaching":"Universal Protocol: verify patient, procedure, site and consent before anything touches the field.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","upsize-035","closure-device"],"outcomes":{"timeout":{"label":"Surgical time-out","score":[{"cat":"technical","delta":0,"reason":"Time-out performed."}],"ok":"Time-out complete — right patient, right procedure, consent on the chart."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol before a time-out.","cite":"Universal Protocol"}],"narrative":"You do something else before the time-out."}},{"n":2,"title":"Sterile prep & drape","node":"rij_access","best":"sterile-prep","prompt":"Prepare the field.","teaching":"The skin is sterilized with a 2% chlorhexidine-based preparation; full surgical scrub protocol (hand scrub, gloves, mask, cap, gown). [1]","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","upsize-035","closure-device"],"outcomes":{"sterile-prep":{"label":"Chlorhexidine prep + full drape","score":[{"cat":"technical","delta":0,"reason":"2% chlorhexidine prep and full sterile drape."}],"ok":"Skin prepped with 2% chlorhexidine; full sterile field up. [1]"}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Procedure not performed under full sterile preparation.","cite":"General considerations [1]"}],"setFlag":"unsterile","narrative":"You press on without full sterile prep."}},{"n":3,"title":"US survey of the right IJ","node":"rij_access","best":"ultrasound","prompt":"Assess the target vein before puncture.","teaching":"Survey the target vein first: patency, compressibility, anatomy. Ultrasound guidance is always recommended for venipuncture. [1]","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","upsize-035","closure-device"],"outcomes":{"ultrasound":{"label":"US survey of the right IJ","imaging":"us","score":[{"cat":"technical","delta":0,"reason":"Pre-puncture US survey of the right IJ."}],"ok":"US survey: right IJ patent, compressible, no thrombus — good target."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"No pre-puncture ultrasound survey of the target vein.","cite":"US guidance is always recommended [1]"}],"narrative":"You skip the vein survey."}},{"n":4,"title":"Venous access","node":"rij_access","best":"us-micropuncture","prompt":"Puncture the right IJ and transition to a working system.","teaching":"Real-time US-guided micropuncture (21G → 0.018 → transitional dilator) is the standard: it is the single biggest pneumothorax/arterial-puncture reducer. [1]","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","upsize-035","closure-device"],"outcomes":{"us-micropuncture":{"label":"US-guided micropuncture (21G), 0.018, transitional dilator","needs":["micropuncture-needle-21g","mp-wire-018","transitional-dilator-5f"],"imaging":"us","complication":{"name":"Pneumothorax","mult":1,"decline":{"sbpDrop":4,"spo2Drop":4,"rrRise":6}},"ok":"Single anterior-wall puncture under real-time US; 0.018 seated; transitioned to the 5F dilator.","hit":"Access obtained, but the post-access check shows a pneumothorax."},"landmark":{"label":"Landmark stick (faster, no US)","needs":["micropuncture-needle-21g"],"score":[{"cat":"technical","delta":-3,"reason":"Landmark venipuncture instead of real-time US guidance.","cite":"US guidance is standard of care [1]"}],"complication":{"name":"Pneumothorax","mult":5,"decline":{"sbpDrop":4,"spo2Drop":4,"rrRise":6}},"ok":"Landmark access happened to work this time.","hit":"Blind stick — the patient desaturates; pneumothorax."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That maneuver does not establish venous access."}],"narrative":"That doesn't get you access."}},{"n":5,"title":"Working wire to the IVC","node":"svc","best":"advance-wire","prompt":"Secure a working guidewire from the access site to the IVC.","teaching":"A working 0.035 guidewire is placed from the access site to the IVC before anything else advances. [1]","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"advance-wire":{"label":"Advance the 0.035 Bentson to the IVC","needs":["bentson-035-145"],"imaging":"tap","score":[{"cat":"technical","delta":0,"reason":"0.035 working wire advanced to the IVC under fluoroscopy."}],"ok":"Bentson advances smoothly; tip parked in the IVC."},"exchange-wire":{"label":"Exchange to a 0.035 hydrophilic working wire","needs":["glidewire-035-150"],"ownedOnly":true,"imaging":"tap","score":[{"cat":"technical","delta":0,"reason":"Exchanged to a hydrophilic working wire (lubricity 9, MODELED)."}],"ok":"The hydrophilic wire glides to the IVC."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"That doesn't secure a working wire to the IVC."}],"narrative":"That doesn't secure the working wire."}},{"n":6,"title":"Anesthetize pocket site & tract","node":"rij_access","best":"local-anesthesia","prompt":"Prepare the chest wall for the pocket and tunnel.","teaching":"Generously anesthetize the intended port site and the whole tunnel tract with 1% lidocaine, with minimal skin entries. [1]","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"local-anesthesia":{"label":"1% lidocaine along pocket site + tunnel tract","score":[{"cat":"technical","delta":0,"reason":"Pocket site and tunnel tract anesthetized."}],"ok":"1% lidocaine along the pocket site and tunnel tract — single skin entry."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Proceeded without anesthetizing the pocket/tract."}],"narrative":"The patient winces — that area isn't numb."}},{"n":7,"title":"Create the port pocket","node":"rij_access","best":"blunt-pocket","prompt":"Create the subcutaneous pocket on the pectoralis fascia.","teaching":"3 cm incision, blunt dissection; the pocket must fit the port without tension — too deep is hard to access, too superficial erodes. Transfuse first if platelets are below 50. [1]","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"blunt-pocket":{"label":"Incise and blunt-dissect a snug pocket","complication":{"name":"Pocket hematoma","multFrom":"platelets","mult":1,"multLow":3,"multVeryLow":8,"decline":{"sbpDrop":6}},"ok":"Pocket created with good hemostasis.","hit":"Oozing in the pocket — a hematoma is developing."},"transfuse":{"label":"Transfuse platelets first, then pocket","transfuse":true}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at pocket creation."}],"narrative":"That isn't how you create the pocket."}},{"n":8,"title":"Tunnel the catheter","node":"rij_access","best":"tunnel","prompt":"Tunnel from the pocket to the neck venotomy.","teaching":"Advance the tunneler from the pocket toward the venotomy in a gentle curve; pull the catheter through. [1]","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"tunnel":{"label":"Tunnel pocket → venotomy, pull the catheter through","needs":["port-catheter-8f"],"score":[{"cat":"technical","delta":0,"reason":"Catheter tunneled from pocket to venotomy in a gentle curve."}],"ok":"The tunneler makes a gentle curve; catheter pulled through to the neck."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at tunneling."}],"narrative":"That isn't the tunneling step."}},{"n":9,"title":"Set tip length to the CAJ","node":"right_bct","best":"measure-trim","prompt":"Determine catheter length so the tip sits at the cavoatrial junction.","teaching":"Measure against the indwelling wire under fluoroscopy and trim — estimating malpositions the tip.","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"measure-trim":{"label":"Measure against the wire under fluoro, trim to the CAJ","imaging":"tap","score":[{"cat":"technical","delta":0,"reason":"Tip length measured to the CAJ under fluoroscopy."}],"ok":"Catheter trimmed so the tip will sit at the cavoatrial junction."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"No fluoroscopic measurement — catheter length estimated (malposition risk)."}],"setFlag":"malposition","narrative":"You end up estimating the length; the tip may sit high."}},{"n":10,"title":"Place the peel-away sheath","node":"svc","best":"place-sheath","prompt":"Place the peel-away introducer over the wire.","teaching":"An appropriately sized peel-away sheath goes over the existing stiff 0.035 wire. An open sheath is an air-embolism risk: breath-hold and pinch it. [1]","blocked":["cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize"],"outcomes":{"place-sheath":{"label":"Peel-away over the wire, breath-hold + pinch","needs":["peelaway-sheath-9f"],"score":[{"cat":"technical","delta":0,"reason":"Peel-away placed with air-embolism precautions (breath-hold, pinched valve)."}],"ok":"Peel-away seated over the stiff wire; dilator out during a breath-hold; sheath pinched. [1]"}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Sloppy sheath handling — no air-embolism precautions.","cite":"Avoiding air embolism [1]"}],"setFlag":"no_air_precautions","narrative":"The sheath goes in without breath-hold discipline; it sits open to air."}},{"n":11,"title":"Advance the catheter to the CAJ","node":"caj","best":"advance-cath","prompt":"Deliver the catheter through the peel-away to the SVC/RA junction.","teaching":"Advance briskly through the peel-away during a breath-hold and position the tip at the SVC/RA junction; keep any open lumen clamped. [1]","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"outcomes":{"advance-cath":{"label":"Advance through the peel-away to the CAJ","ifFlag":"no_air_precautions","ifFlagEvent":{"name":"Air embolism","decline":{"sbpDrop":18,"spo2Drop":6,"rrRise":4},"riskPct":60,"note":"Open, unpinched sheath entrained air during catheter delivery (step 10 precaution skipped). MODELED event."},"ifFlagHit":"As the catheter goes in through the open sheath there's a gasp — air embolism.","ifFlagNarrative":"The catheter goes in through the open sheath — you get away with it this time.","score":[{"cat":"technical","delta":0,"reason":"Catheter advanced through the peel-away to the SVC/RA junction."}],"ok":"Advanced during a breath-hold; tip at the CAJ; sheath peeled away."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at catheter delivery."}],"narrative":"That isn't catheter delivery."}},{"n":12,"title":"Attach the catheter to the port","node":"caj","best":"connect-device","prompt":"Assemble the system and seat the port.","teaching":"Cut the tubing at the pocket, attach it to the reservoir and secure the hub — enough slack to connect, not enough to kink. Lower the port into the pocket. [1]","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"outcomes":{"connect-device":{"label":"Trim, lock to the port stem, seat the port","score":[{"cat":"technical","delta":0,"reason":"Catheter cut to length, secured to the port hub; port seated."}],"ok":"Tubing trimmed at the pocket, locked to the port stem; port lowered in without kinks. [1]"}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at port assembly."}],"narrative":"That doesn't assemble the port."}},{"n":13,"title":"Access & test the port","node":"caj","best":"aspirate","prompt":"Verify function before closing.","teaching":"Access with a noncoring (Huber) needle; aspirate and flush each lumen; instill heparin lock per policy. [1]","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"outcomes":{"aspirate":{"label":"Huber access; aspirate + flush each lumen","needs":["huber-needle-20g"],"score":[{"cat":"technical","delta":0,"reason":"Brisk blood return and free flush confirmed."}],"ok":"Huber in; brisk aspiration, free flush, heparin lock instilled. No pocket swelling."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Port function not verified before closure."}],"narrative":"That doesn't verify port function."}},{"n":14,"title":"Confirm tip & close","node":"caj","best":"dsa","prompt":"Confirm final tip position and close.","teaching":"Save a completion spot image documenting tip position, then a two-layer pocket closure. [1]","blocked":["cat:embolization","cat:angioplasty"],"outcomes":{"dsa":{"label":"DSA spot to document the CAJ tip, then two-layer close","imaging":"dsa","contrastMl":3,"ifFlag":"malposition","ifFlagScore":[{"cat":"technical","delta":-3,"reason":"Malpositioned tip required repositioning before closure."}],"ifFlagImaging":"reposition","ifFlagNarrative":"The spot shows the tip sitting high; repositioned to the CAJ, then closed in two layers.","elseScore":[{"cat":"technical","delta":0,"reason":"Completion image documents the CAJ tip without kinks."}],"elseNarrative":"Tip confirmed at the CAJ; pocket closed in two layers."},"completion":{"label":"Completion angiogram, then two-layer close","imaging":"dsa","contrastMl":3,"ifFlag":"malposition","ifFlagScore":[{"cat":"technical","delta":-3,"reason":"Malpositioned tip required repositioning before closure."}],"ifFlagImaging":"reposition","ifFlagNarrative":"The completion run shows the tip sitting high; repositioned to the CAJ, then closed.","elseScore":[{"cat":"technical","delta":0,"reason":"Completion image documents the CAJ tip without kinks."}],"elseNarrative":"Tip confirmed at the CAJ; pocket closed in two layers."},"close":{"label":"Close without a confirmatory image","score":[{"cat":"technical","delta":-6,"reason":"Closed without documenting final tip position."}],"ifFlag":"malposition","ifFlagScore":[{"cat":"safety","delta":0,"reason":"Undocumented malpositioned tip left in place."}],"narrative":"You close without a confirmatory spot film."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"Off-protocol at closure."}],"narrative":"That isn't the confirm/close step."}}]$steps$::jsonb
where procedure_id = 'chest-port';

-- UFE: IR suite. Preop rules MODELED pending citation. min_level 2 DESIGN.
update public.procedure_game_params set
  min_level = 2, location = 'ir_suite',
  preop = $steps${"labs":[{"id":"inr","label":"INR","kind":"max","limit":1.5,"required":true,"canBeMissing":true,"goalText":"goal < 1.5 (moderate bleeding risk)","cite":"MODELED — pending citation (SIR moderate-risk convention)","derange":[1.7,3],"violation":{"score":[{"cat":"safety","delta":-6,"reason":"Proceeded with INR above the 1.5 goal without correction.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":3,"basis":"MODELED multiplier"}]},"missingViolation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded without a documented INR.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":1.5,"basis":"MODELED multiplier"}]}},{"id":"platelets","label":"Platelet count","kind":"min","limit":50,"required":false,"goalText":"transfuse if < 50 ×10⁹/L","cite":"MODELED — pending citation (SIR moderate-risk convention)","derange":[24,46],"violation":{"score":[{"cat":"safety","delta":-5,"reason":"Proceeded with platelets < 50 ×10⁹/L without transfusion.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":3,"basis":"MODELED multiplier"}]}}],"contraindications":[{"id":"pregnancy","label":"Viable pregnancy","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"This morning's β-hCG returned positive; bedside ultrasound shows an early intrauterine pregnancy.","violation":{"score":[{"cat":"safety","delta":-15,"reason":"Embolized the uterine arteries of a pregnant patient.","cite":"MODELED — pending citation"}],"postop":"Pregnancy loss attributed to uterine devascularization — root-cause analysis opened."}},{"id":"pelvic_infection","label":"Active pelvic infection","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"Purulent cervical discharge with uterine tenderness; WBC 15.8 — gynecology is treating active PID.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Embolized a uterus with active pelvic infection.","cite":"MODELED — pending citation"}],"postop":"Pyometra requiring hysterectomy — infected, devascularized tissue."}},{"id":"gyn_malignancy","label":"Suspected gynecologic malignancy","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"Rapidly enlarging uterine mass with irregular enhancement and ascites — malignancy not yet excluded; biopsy pending.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Embolized a mass suspicious for malignancy before tissue diagnosis.","cite":"MODELED — pending citation"}],"postop":"Final pathology: leiomyosarcoma — embolization delayed the oncologic diagnosis."}}]}$steps$::jsonb,
  case_steps = $steps$[{"n":1,"title":"Time-out & planning","node":"cfa_access","best":"timeout","prompt":"Symptomatic fibroids, MRI reviewed. Begin the case.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","closure-device"],"teaching":"Confirm symptomatic fibroids, patent uterine ostia, and no dominant ovarian supply before starting.","outcomes":{"timeout":{"label":"Pre-procedure time-out; confirm MRI, symptoms, consent","note":"Correct","ok":"MRI shows dominant fundal fibroids with patent uterine arteries. Consent confirmed."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Skipped the pre-procedure time-out."}],"narrative":"You skip the checklist and press on."}},{"n":2,"title":"Femoral access","node":"cfa_access","best":"us-micropuncture","prompt":"Obtain arterial access and place a working sheath.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"teaching":"Ultrasound-guided common femoral access lowers access-site complications.","outcomes":{"us-micropuncture":{"label":"Ultrasound-guided common femoral access, 5F sheath","note":"Standard of care","needs":["micropuncture-needle-21g","vascular-sheath-5f"],"imaging":"us","ok":"Single anterior-wall CFA puncture under ultrasound; 5F sheath placed."},"landmark":{"label":"Landmark femoral stick without ultrasound","note":"Off-standard","needs":["micropuncture-needle-21g","vascular-sheath-5f"],"score":[{"cat":"technical","delta":-3,"reason":"Femoral access without ultrasound guidance.","cite":"US-guided access reduces access-site complications"}],"ok":"Access obtained by palpation; sheath placed."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That does not obtain arterial access."}],"narrative":"That won't get you into the femoral artery."}},{"n":3,"title":"Pelvic arteriogram","node":"aortic_bifurc","best":"dsa","prompt":"Map the uterine arteries before selecting.","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"teaching":"A diagnostic pelvic run identifies the uterine origins and any ovarian collateral supply.","outcomes":{"dsa":{"label":"Pelvic DSA through a flush catheter","note":"Correct roadmap","needs":["pigtail-flush-5f","bentson-035-145"],"imaging":"dsa","contrastMl":12,"ok":"Pelvic arteriogram maps both uterine arteries; no dominant ovarian supply."},"fluoro":{"label":"A quick fluoro spot instead of a full run","note":"Inadequate roadmap","imaging":"fluoro","score":[{"cat":"technical","delta":-3,"reason":"No diagnostic pelvic arteriogram before selection."}],"ok":"You skip the full run and start poking around."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"No pelvic roadmap obtained."}],"narrative":"You proceed without mapping the anatomy."}},{"n":4,"title":"Select the uterine artery","node":"contra_iia","best":"reform","prompt":"Catheterize the (contralateral) uterine artery.","blocked":["cat:embolization","cat:angioplasty"],"teaching":"A reverse-curve catheter reforms to select the sharply reflexed uterine origin up-and-over the bifurcation.","outcomes":{"reform":{"label":"Reform a reverse-curve catheter into the uterine artery","note":"Correct","needs":["sos-omni-5f","stiff-glidewire-035"],"imaging":"fluoro","ok":"Reverse curve reformed; up-and-over to the contralateral internal iliac, then into the uterine artery."},"advance-cath":{"label":"Push a straight catheter at the origin","note":"Wrong shape for this angle","score":[{"cat":"technical","delta":-3,"reason":"A straight catheter cannot hold the sharply reflexed uterine origin."}],"ok":"The straight catheter keeps prolapsing out — no stable selection."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at uterine selection."}],"narrative":"That doesn't select the uterine artery."}},{"n":5,"title":"Superselect","node":"uterine_origin","best":"superselect","prompt":"Position a microcatheter for embolization.","teaching":"Advancing distal to the cervicovaginal branch protects nontarget bladder/vaginal territory.","outcomes":{"superselect":{"label":"Microcatheter distal to the cervicovaginal branch","note":"Correct — protects nontarget territory","needs":["microcatheter-27-150"],"imaging":"fluoro","ok":"Microcatheter parked in the horizontal segment, beyond the cervicovaginal branch."},"advance-micro":{"label":"Microcatheter only to the proximal uterine artery","note":"Proximal — higher nontarget risk","needs":["microcatheter-27-150"],"imaging":"fluoro","setFlag":"proximal_embo","score":[{"cat":"technical","delta":-2,"reason":"Proximal microcatheter position raises nontarget/ovarian collateral risk."}],"ok":"Microcatheter sits proximally, near the cervicovaginal origin."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at superselection."}],"narrative":"That doesn't superselect the uterine artery."}},{"n":6,"title":"Embolize to near-stasis","node":"uterine_target","best":"particles","prompt":"Devascularize the fibroids.","teaching":"Calibrated spheres to a slow-flow, pruned-tree endpoint — stop before stasis to limit reflux.","outcomes":{"particles":{"label":"Inject calibrated microspheres to a pruned-tree endpoint","note":"Correct endpoint","needs":["microspheres-500-700"],"imaging":"fluoro","contrastMl":6,"complication":{"name":"Nontarget embolization (bladder, vagina, skin)","mult":1,"decline":{"sbpDrop":2}},"ok":"500–700 µm spheres to a slow-flow, pruned-tree endpoint.","hit":"A little reflux — some spheres reach the bladder/vaginal branches."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That does not embolize the fibroid bed appropriately (e.g., a proximal coil leaves collateral supply)."}],"narrative":"That isn't the right way to devascularize the fibroids."}},{"n":7,"title":"Contralateral side","node":"uterine_target","best":"reform","prompt":"Treat the other uterine artery.","teaching":"Bilateral treatment is standard — unilateral UFE has high recurrence.","outcomes":{"reform":{"label":"Select and embolize the opposite uterine artery to the same endpoint","note":"Bilateral is standard","imaging":"fluoro","contrastMl":6,"complication":{"name":"Ovarian insufficiency","mult":1,"decline":{}},"ok":"Contralateral uterine artery selected and embolized to near-stasis; bilateral treatment complete.","hit":"Diffuse embolization compromises some ovarian arterial supply."},"close":{"label":"Close up after treating only the accessed side","note":"Undertreatment","score":[{"cat":"technical","delta":-5,"reason":"Unilateral UFE — high recurrence; both uterine arteries should be treated."}],"ok":"You stop after one side."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol before treating the second side."}],"narrative":"That doesn't address the contralateral uterine artery."}},{"n":8,"title":"Completion & closure","node":"cfa_access","best":"closure-device","prompt":"Finish the case.","teaching":"A completion run documents bilateral devascularization; both closure devices and manual pressure are acceptable.","outcomes":{"closure-device":{"label":"Completion pelvic run, then a closure device","note":"Correct","needs":["collagen-plug-closure"],"imaging":"dsa","contrastMl":5,"ok":"Completion run confirms bilateral devascularization; collagen-plug closure with good hemostasis. Expect post-embolization syndrome (cramping, low-grade fever) — managed with NSAIDs/anti-emetics on the ward."},"manual-closure":{"label":"Completion run, then hold manual pressure","note":"Also acceptable","imaging":"dsa","contrastMl":5,"ok":"Completion run good; ~15 minutes of manual pressure to hemostasis."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"Closed without a completion angiogram."}],"narrative":"You close without documenting the result."}}]$steps$::jsonb
where procedure_id = 'uterine-fibroid-embolization';

